import { useNavigate } from "react-router-dom";

function Login() {
  const navigate = useNavigate();

  const handleLogin = (role) => {
    localStorage.setItem("role", role);

    if (role === "admin") navigate("/admin");
    if (role === "instructor") navigate("/instructor");
    if (role === "student") navigate("/student");
    if (role === "content") navigate("/content");
  };

  return (
    <div className="container d-flex justify-content-center align-items-center vh-100">
      <div className="card p-4 shadow" style={{ width: "400px" }}>
        <h3 className="text-center mb-4">NexaLearn LMS</h3>

        <button className="btn btn-primary mb-2 w-100" onClick={() => handleLogin("admin")}>
          Login as Admin
        </button>

        <button className="btn btn-success mb-2 w-100" onClick={() => handleLogin("instructor")}>
          Login as Instructor
        </button>

        <button className="btn btn-warning mb-2 w-100" onClick={() => handleLogin("student")}>
          Login as Student
        </button>

        <button className="btn btn-dark w-100" onClick={() => handleLogin("content")}>
          Login as Content Creator
        </button>
      </div>
    </div>
  );
}

export default Login;
